SELECT id, public_id, tenant_id, workspace_id, owner_user_id, title, status, latest_revision, deleted_at, created_at, updated_at
FROM documents
WHERE public_id = #{publicId} AND tenant_id = #{tenantId} AND workspace_id = #{workspaceId}

SELECT id, document_id, revision, content, content_hash, created_by, created_at
FROM document_revisions
WHERE document_id = #{documentId} AND revision = #{revision}
